$function$;

CREATE OR REPLACE FUNCTION cad_ut.test_scene_json()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_did int;
  v_pid int;
  v_json jsonb;
  v_piece jsonb;
BEGIN
  INSERT INTO cad.drawing (name) VALUES ('test_scene') RETURNING id INTO v_did;

  -- Empty drawing
  v_json := cad.scene_json(v_did);
  RETURN NEXT ok(v_json IS NOT NULL, 'scene_json returns jsonb');
  RETURN NEXT is((v_json->'pieces')::text, '[]'::text, 'empty drawing has empty pieces');
  RETURN NEXT is((v_json->'groups')::text, '[]'::text, 'empty drawing has empty groups');

  -- Add a beam
  v_pid := cad.add_beam(v_did, '60x90', ARRAY[0,0,0]::real[], ARRAY[1000,0,0]::real[], 'P1', 'montant', 'chene');
  v_json := cad.scene_json(v_did);
  RETURN NEXT is(jsonb_array_length(v_json->'pieces'), 1, 'one piece in scene');

  v_piece := v_json->'pieces'->0;
  RETURN NEXT is((v_piece->>'label'), 'P1', 'piece label');
  RETURN NEXT is((v_piece->>'role'), 'montant', 'piece role');
  RETURN NEXT is((v_piece->>'wood_type'), 'chene', 'piece wood_type');
  RETURN NEXT is((v_piece->>'section'), '60x90', 'piece section');
  RETURN NEXT ok(v_piece->'mesh' IS NOT NULL, 'piece has mesh');
  RETURN NEXT ok((v_piece->'mesh'->>'type') = 'GeometryCollection', 'mesh is GeometryCollection');

  -- Add group
  PERFORM cad.group_pieces(v_did, ARRAY[v_pid], 'Mur1');
  v_json := cad.scene_json(v_did);
  RETURN NEXT is(jsonb_array_length(v_json->'groups'), 1, 'one group in scene');
  RETURN NEXT is((v_json->'groups'->0->>'label'), 'Mur1', 'group label');
  RETURN NEXT is((v_json->'pieces'->0->>'group_label'), 'Mur1', 'piece has group_label');
END;
$function$;
COMMENT ON FUNCTION cad_ut.test_scene_json() IS 'Test cad.scene_json: empty, single piece, grouped piece, mesh format';

CREATE OR REPLACE FUNCTION cad_ut.test_shape_add()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_did int;
  v_lid int;
  v_result text;
  v_count int;
BEGIN
  -- Setup: create drawing + layer
  INSERT INTO cad.drawing (name) VALUES ('test_shape_add') RETURNING id INTO v_did;
  INSERT INTO cad.layer (drawing_id, name, color, stroke_width)
  VALUES (v_did, 'L1', '#000', 1) RETURNING id INTO v_lid;

  -- Test: missing params returns error
  v_result := cad.post_shape_add(v_did, NULL, NULL);
  RETURN NEXT ok(v_result LIKE '%data-toast="error"%', 'missing params returns error');

  -- Test: invalid geometry JSON returns error
  v_result := cad.post_shape_add(v_did, v_lid, 'line', '{bad json}');
  RETURN NEXT ok(v_result LIKE '%Géométrie JSON invalide%', 'bad geometry returns error');

  -- Test: invalid props JSON returns error
  v_result := cad.post_shape_add(v_did, v_lid, 'line', '{"x1":0}', '{bad}');
  RETURN NEXT ok(v_result LIKE '%Props JSON invalides%', 'bad props returns error');

  -- Test: valid shape_add returns success + redirect
  v_result := cad.post_shape_add(v_did, v_lid, 'line', '{"x1":0,"y1":0,"x2":100,"y2":0}', '{}', 'TestLine');
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'valid add returns success toast');
  RETURN NEXT ok(v_result LIKE '%data-redirect%', 'valid add returns redirect');

  -- Test: shape exists in DB
  SELECT count(*) INTO v_count FROM cad.shape WHERE drawing_id = v_did AND label = 'TestLine';
  RETURN NEXT is(v_count, 1, 'shape created in DB');

  -- Cleanup
  DELETE FROM cad.shape WHERE drawing_id = v_did;
  DELETE FROM cad.layer WHERE drawing_id = v_did;
  DELETE FROM cad.drawing WHERE id = v_did;
END;
$function$;
COMMENT ON FUNCTION cad_ut.test_shape_add() IS 'Test RPC post_shape_add: validates creation, error on missing params, JSON parse errors.';

CREATE OR REPLACE FUNCTION cad_ut.test_shape_delete()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_did int;
  v_lid int;
  v_sid int;
  v_result text;
  v_count int;
BEGIN
  -- Setup
  INSERT INTO cad.drawing (name) VALUES ('test_shape_delete') RETURNING id INTO v_did;
  INSERT INTO cad.layer (drawing_id, name, color, stroke_width)
  VALUES (v_did, 'L1', '#000', 1) RETURNING id INTO v_lid;
  v_sid := cad.add_shape(v_did, v_lid, 'rect', '{"x":0,"y":0,"w":50,"h":30}'::jsonb);

