CREATE OR REPLACE FUNCTION cad_ut.test_group_shapes()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_drawing_id int;
  v_layer_id int;
  v_s1 int; v_s2 int; v_s3 int;
  v_group_id int;
  v_svg text;
  v_count int;
BEGIN
  -- Setup
  INSERT INTO cad.drawing (name) VALUES ('test_group') RETURNING id INTO v_drawing_id;
  INSERT INTO cad.layer (drawing_id, name) VALUES (v_drawing_id, 'default') RETURNING id INTO v_layer_id;
  
  v_s1 := cad.add_shape(v_drawing_id, v_layer_id, 'line', '{"x1":0,"y1":0,"x2":100,"y2":0}');
  v_s2 := cad.add_shape(v_drawing_id, v_layer_id, 'line', '{"x1":100,"y1":0,"x2":100,"y2":100}');
  v_s3 := cad.add_shape(v_drawing_id, v_layer_id, 'rect', '{"x":200,"y":200,"w":50,"h":50}');

  -- Test group_shapes
  v_group_id := cad.group_shapes(v_drawing_id, ARRAY[v_s1, v_s2], 'Mur nord');
  RETURN NEXT ok(v_group_id IS NOT NULL, 'group created');
  RETURN NEXT ok(
    (SELECT type FROM cad.shape WHERE id = v_group_id) = 'group',
    'group type is group'
  );
  RETURN NEXT ok(
    (SELECT count(*) FROM cad.shape WHERE parent_id = v_group_id) = 2,
    'group has 2 children'
  );
  RETURN NEXT ok(
    (SELECT parent_id FROM cad.shape WHERE id = v_s3) IS NULL,
    's3 not in group'
  );

  -- Test SVG rendering with group
  v_svg := cad.render_svg(v_drawing_id);
  RETURN NEXT ok(v_svg LIKE '%data-group-id="' || v_group_id || '"%', 'svg contains group element');
  RETURN NEXT ok(v_svg LIKE '%data-label="Mur nord"%', 'group label rendered');

  -- Test move_group
  v_count := cad.move_group(v_group_id, 10, 20);
  RETURN NEXT is(v_count, 2, 'move_group moved 2 shapes');
  RETURN NEXT is(
    (SELECT (geometry->>'x1')::real FROM cad.shape WHERE id = v_s1),
    10::real, 'shape x1 moved +10'
  );

  -- Test ungroup
  v_count := cad.ungroup(v_group_id);
  RETURN NEXT is(v_count, 2, 'ungroup detached 2 shapes');
  RETURN NEXT ok(
    NOT EXISTS (SELECT 1 FROM cad.shape WHERE id = v_group_id),
    'group shape deleted'
  );
  RETURN NEXT ok(
    (SELECT parent_id FROM cad.shape WHERE id = v_s1) IS NULL,
    's1 detached after ungroup'
  );

  -- Cleanup
  DELETE FROM cad.drawing WHERE id = v_drawing_id;
END;
$function$;

CREATE OR REPLACE FUNCTION cad_ut.test_group_pieces()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_did int;
  v_p1 int; v_p2 int; v_p3 int; v_p4 int;
  v_gid int; v_gid2 int;
  v_count int;
  v_z_before real; v_z_after real;
BEGIN
  -- Setup: dessin + 4 pièces
  INSERT INTO cad.drawing (name) VALUES ('test_groups') RETURNING id INTO v_did;
  v_p1 := cad.add_piece(v_did, '60x60', 2000, ARRAY[0,0,0]::real[], ARRAY[0,0,0]::real[], 'P1', 'poteau');
  v_p2 := cad.add_piece(v_did, '60x60', 2000, ARRAY[1000,0,0]::real[], ARRAY[0,0,0]::real[], 'P2', 'poteau');
  v_p3 := cad.add_piece(v_did, '45x90', 1060, ARRAY[0,0,2000]::real[], ARRAY[0,90,0]::real[], 'T1', 'traverse');
  v_p4 := cad.add_piece(v_did, '45x90', 1060, ARRAY[0,0,2500]::real[], ARRAY[0,90,0]::real[], 'T2', 'traverse');

  -- Test 1: group_pieces
  v_gid := cad.group_pieces(v_did, ARRAY[v_p1, v_p2], 'Poteaux');
  RETURN NEXT ok(v_gid IS NOT NULL, 'group_pieces returns group_id');
  SELECT count(*) INTO v_count FROM cad.piece WHERE group_id = v_gid;
  RETURN NEXT is(v_count, 2, 'group has 2 pieces');

  -- Test 2: rename_group
  PERFORM cad.rename_group(v_gid, 'Poteaux Mur Nord');
  RETURN NEXT is(
    (SELECT label FROM cad.piece_group WHERE id = v_gid),
    'Poteaux Mur Nord', 'rename_group works'
  );

  -- Test 3: list_groups
  RETURN NEXT ok(
    cad.list_groups(v_did) LIKE '%Poteaux Mur Nord%',
    'list_groups shows group'
  );

  -- Test 4: move_group_pieces
  SELECT ST_ZMin(geom) INTO v_z_before FROM cad.piece WHERE id = v_p1;
  PERFORM cad.move_group_pieces(v_gid, 0, 0, 500);
  SELECT ST_ZMin(geom) INTO v_z_after FROM cad.piece WHERE id = v_p1;
  RETURN NEXT ok(abs(v_z_after - v_z_before - 500) < 1, 'move_group_pieces translates pieces');

  -- Test 5: duplicate_group
  v_gid2 := cad.duplicate_group(v_gid, 0, 2000, 0);
  RETURN NEXT ok(v_gid2 IS NOT NULL AND v_gid2 <> v_gid, 'duplicate_group creates new group');
  SELECT count(*) INTO v_count FROM cad.piece WHERE group_id = v_gid2;
  RETURN NEXT is(v_count, 2, 'duplicated group has 2 pieces');

  -- Test 6: nest_group
  PERFORM cad.nest_group(v_gid2, v_gid);
  RETURN NEXT is(
    (SELECT parent_id FROM cad.piece_group WHERE id = v_gid2),
    v_gid, 'nest_group sets parent_id'
  );

  -- Test 7: ungroup_pieces
  v_count := cad.ungroup_pieces(v_gid2);
  RETURN NEXT is(v_count, 2, 'ungroup_pieces detaches pieces');
  RETURN NEXT ok(
    NOT EXISTS (SELECT 1 FROM cad.piece_group WHERE id = v_gid2),
    'ungroup_pieces deletes group'
  );

  -- Test 8: remove_group with pieces
  v_gid2 := cad.group_pieces(v_did, ARRAY[v_p3, v_p4], 'Traverses');
  PERFORM cad.remove_group(v_gid2, false);
  RETURN NEXT ok(
    NOT EXISTS (SELECT 1 FROM cad.piece WHERE id IN (v_p3, v_p4)),
    'remove_group(keep:=false) deletes pieces'
  );

  -- Cleanup
  DELETE FROM cad.drawing WHERE id = v_did;
END;
$function$;
COMMENT ON FUNCTION cad_ut.test_group_pieces() IS 'Test pgTAP pour le systeme de groupes de pieces 3D.';

GRANT USAGE ON SCHEMA cad_ut TO anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA cad_ut TO anon;
GRANT SELECT ON ALL TABLES IN SCHEMA cad_ut TO anon;
